#include <stdio.h>
#include <stdlib.h>

#define MAX_V 100

typedef struct {
    int vertices;
    int adj[MAX_V][MAX_V];
    int inDegree[MAX_V];
} Graph;

void initGraph(Graph* g, int v) {
    g->vertices = v;
    for (int i = 0; i < v; i++) {
        g->inDegree[i] = 0;
        for (int j = 0; j < v; j++)
            g->adj[i][j] = 0;
    }
}

void addEdge(Graph* g, int u, int v) {
    g->adj[u][v] = 1;
    g->inDegree[v]++;
}

int* topologicalSort(Graph* g) {
    int* result = malloc(g->vertices * sizeof(int));
    int count = 0;

    // Queue implementation
    int queue[MAX_V];
    int front = 0, rear = 0;

    // Add all vertices with in-degree 0 to queue
    for (int i = 0; i < g->vertices; i++) {
        if (g->inDegree[i] == 0)
            queue[rear++] = i;
    }

    while (front < rear) {
        int u = queue[front++];
        result[count++] = u;

        for (int v = 0; v < g->vertices; v++) {
            if (g->adj[u][v]) {
                g->inDegree[v]--;
                if (g->inDegree[v] == 0)
                    queue[rear++] = v;
            }
        }
    }

    if (count != g->vertices) {
        printf("Graph contains a cycle!\n");
        free(result);
        return NULL;
    }

    return result;
}

int main() {
    Graph g;
    initGraph(&g, 6);
    addEdge(&g, 0, 1);  // A -> B
    addEdge(&g, 0, 2);  // A -> C
    addEdge(&g, 1, 3);  // B -> D
    addEdge(&g, 2, 3);  // C -> D
    addEdge(&g, 3, 4);  // D -> E
    addEdge(&g, 2, 5);  // C -> F

    int* result = topologicalSort(&g);
    if (result) {
        printf("Topological Order: ");
        for (int i = 0; i < g.vertices; i++)
            printf("%c ", 'A' + result[i]);
    }

    return 0;
}

import java.util.*;

public class CycleDetection {

    public static boolean hasCycle(int vertices, List<int[]> edges) {
        // Build adjacency list and in-degree array
        List<List<Integer>> adj = new ArrayList<>();
        int[] inDegree = new int[vertices];

        for (int i = 0; i < vertices; i++)
            adj.add(new ArrayList<>());

        for (int[] edge : edges) {
            int u = edge[0];
            int v = edge[1];
            adj.get(u).add(v);
            inDegree[v]++;
        }

        // Kahn's algorithm for cycle detection
        Queue<Integer> queue = new LinkedList<>();

        // Add all vertices with in-degree 0
        for (int i = 0; i < vertices; i++) {
            if (inDegree[i] == 0)
                queue.offer(i);
        }

        int processed = 0;

        while (!queue.isEmpty()) {
            int current = queue.poll();
            processed++;

            for (int neighbor : adj.get(current)) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0)
                    queue.offer(neighbor);
            }
        }

        // If not all vertices processed, cycle exists
        return processed != vertices;
    }

    public static void main(String[] args) {
        // Example 1: DAG
        List<int[]> dagEdges = Arrays.asList(
            new int[]{0, 1}, new int[]{0, 2},
            new int[]{1, 3}, new int[]{2, 3}
        );

        // Example 2: Cyclic graph
        List<int[]> cyclicEdges = Arrays.asList(
            new int[]{0, 1}, new int[]{1, 2},
            new int[]{2, 0}
        );

        System.out.println("DAG has cycle: " + hasCycle(4, dagEdges));
        System.out.println("Cyclic graph has cycle: " + hasCycle(3, cyclicEdges));
    }
}
